import React, { useState } from 'react';

const App = () => {
  const [articles, setArticles] = useState([]);
  const [filter, setFilter] = useState('');
  const [sort, setSort] = useState('rating');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#f4f4f4] p-4 w-[800px] max-w-full">
        <h1 className="text-3xl font-bold mb-4">Article List</h1>
        <div className="flex flex-wrap justify-between mb-4">
          <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" onClick={() => setFilter('')}>All Categories</button>
          <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" onClick={() => setFilter('Category 1')}>Category 1</button>
          <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" onClick={() => setFilter('Category 2')}>Category 2</button>
        </div>
        <select className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" value={sort} onChange={(e) => setSort(e.target.value)}>
          <option value="rating">Rating</option>
          <option value="title">Title</option>
          <option value="author">Author</option>
        </select>
        <ul className="list-none mb-4">
          {articles.map((article, index) => (
            <li key={index} className="bg-[#B7D7CD] p-4 mb-4">
              <h2 className="text-2xl font-bold mb-2">{article.title}</h2>
              <p className="text-lg font-bold mb-2">{article.author}</p>
              <p className="text-lg font-bold mb-2">Rating: {article.rating}</p>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
